#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int inf=0x3f3f3f3f;
int n,m,ans=inf,dp[(1<<10)+5][2];
string s[1005];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>s[i];
		s[i]=" "+s[i];
	}
	for(int k=1;k<(1<<m);k++) dp[k][0]=inf;
	int cnt=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			cnt++;
			for(int k=0;k<(1<<m);k++) dp[k][cnt%2]=inf;
			for(int k=0;k<(1<<m);k++)
			{
				int cost=dp[k][(cnt+1)%2];
//				cout<<"dp "<<k<<" "<<cnt<<" :\n  cost : "<<cost<<"\n";
				if((k&(1<<(j-1)))==0)
				{
//					cout<<"  a\n";
					if(s[i][j]=='#'&&((s[i][j-1]!='#')||(k&(1<<(j-2)))))
					{
						dp[k][cnt%2]=1;
//						cout<<"    aa\n";
					}
					else
					{
						dp[k][cnt%2]=0;
//						cout<<"    ab\n";
					}
					dp[k][cnt%2]+=min(cost,dp[k^(1<<(j-1))][(cnt+1)%2]);
				}
				else
				{
//					cout<<"  b\n";
					if(s[i][j]!='#')
					{
						dp[k][cnt%2]=inf;
//						cout<<"    ba\n";
					}
					else
					{
						dp[k][cnt%2]=min(cost,dp[k^(1<<(j-1))][(cnt+1)%2]+1);
//						cout<<"    bb\n";
					}
				}
//				cout<<"dp_num : "<<dp[k][cnt%2]<<"\n";
			}
		}
	}
	for(int k=0;k<(1<<m);k++) ans=min(ans,dp[k][cnt%2]);
	cout<<ans;
	return 0;
}
